/**
 * Email notification adapter — delivers notifications via email.
 *
 * Implements template rendering for each notification type, recipient
 * validation, and structured email delivery through a configurable
 * transport. In non-production environments, emails are captured in
 * memory for testing and inspection.
 */

import type { NotificationPayload, NotificationResult, NotificationType } from '../models/notification.js';
import type { NotificationAdapter } from './notification.adapter.js';
import { Logger } from '../utils/logger.js';

export interface EmailConfig {
  /** SMTP host (e.g. 'smtp.example.com'). */
  host: string;
  /** SMTP port (e.g. 587). */
  port: number;
  /** Sender email address. */
  from: string;
  /** Sender display name. */
  fromName?: string;
  /** Reply-to address (defaults to from). */
  replyTo?: string;
}

export const defaultEmailConfig: EmailConfig = {
  host: 'localhost',
  port: 587,
  from: 'noreply@taskflowpro.com',
  fromName: 'TaskFlow Pro',
};

/** Structured email ready for transport. */
export interface RenderedEmail {
  from: string;
  to: string;
  replyTo: string;
  subject: string;
  html: string;
  text: string;
  headers: Record<string, string>;
}

/** A sent email record for inspection/testing. */
export interface SentEmail {
  payload: NotificationPayload;
  rendered: RenderedEmail;
  sentAt: Date;
}

/**
 * Validate an email address format.
 * Checks for basic structure: non-empty local part, @, domain with dot.
 */
export function isValidEmail(email: string): boolean {
  if (!email || typeof email !== 'string') return false;
  const parts = email.split('@');
  if (parts.length !== 2) return false;
  const [local, domain] = parts;
  if (!local || !domain) return false;
  if (domain.indexOf('.') === -1) return false;
  if (local.length > 64 || domain.length > 253) return false;
  return true;
}

/**
 * Resolve a recipient identifier to a deliverable email address.
 * If the recipient is already a valid email, use it directly.
 * Otherwise, treat it as a user ID and use metadata to find the email.
 */
export function resolveRecipient(
  recipient: string,
  metadata?: Record<string, unknown>,
): string | null {
  if (isValidEmail(recipient)) {
    return recipient;
  }

  // Check metadata for an email override
  if (metadata?.email && typeof metadata.email === 'string' && isValidEmail(metadata.email)) {
    return metadata.email;
  }

  // Could not resolve — recipient is not a valid email and no fallback available
  return null;
}

/** Template rendering context built from the notification payload. */
interface TemplateContext {
  subject: string;
  body: string;
  recipient: string;
  priority: string;
  metadata: Record<string, unknown>;
}

/**
 * Render an HTML email from a notification payload.
 * Each notification type has its own template section.
 */
export function renderTemplate(type: NotificationType, ctx: TemplateContext): { html: string; text: string } {
  const text = ctx.body;

  const priorityBanner =
    ctx.priority === 'high' || ctx.priority === 'urgent'
      ? `<div style="background:#d32f2f;color:#fff;padding:8px 16px;font-weight:bold;">Priority: ${ctx.priority.toUpperCase()}</div>`
      : '';

  let contentHtml: string;

  switch (type) {
    case 'order_confirmation': {
      const orderId = ctx.metadata.orderId ?? '';
      contentHtml = [
        `<h2>Order Confirmation</h2>`,
        `<p>Thank you for your order <strong>${escapeHtml(String(orderId))}</strong>.</p>`,
        `<p>${escapeHtml(ctx.body)}</p>`,
      ].join('\n');
      break;
    }
    case 'order_status_update': {
      const prev = ctx.metadata.previousStatus ?? '';
      const next = ctx.metadata.newStatus ?? '';
      contentHtml = [
        `<h2>Order Status Update</h2>`,
        `<p>Your order status has changed from <strong>${escapeHtml(String(prev))}</strong> to <strong>${escapeHtml(String(next))}</strong>.</p>`,
        `<p>${escapeHtml(ctx.body)}</p>`,
      ].join('\n');
      break;
    }
    case 'welcome': {
      contentHtml = [
        `<h2>Welcome to TaskFlow Pro!</h2>`,
        `<p>${escapeHtml(ctx.body)}</p>`,
        `<p>Get started by visiting your <a href="https://app.taskflowpro.com/dashboard">dashboard</a>.</p>`,
      ].join('\n');
      break;
    }
    case 'account_updated': {
      contentHtml = [
        `<h2>Account Updated</h2>`,
        `<p>${escapeHtml(ctx.body)}</p>`,
      ].join('\n');
      break;
    }
    default: {
      contentHtml = `<p>${escapeHtml(ctx.body)}</p>`;
    }
  }

  const html = [
    `<!DOCTYPE html>`,
    `<html><head><meta charset="utf-8"></head>`,
    `<body style="font-family:sans-serif;max-width:600px;margin:0 auto;">`,
    priorityBanner,
    contentHtml,
    `<hr><p style="color:#888;font-size:12px;">This is an automated message from TaskFlow Pro.</p>`,
    `</body></html>`,
  ].join('\n');

  return { html, text };
}

function escapeHtml(str: string): string {
  return str
    .replace(/&/g, '&amp;')
    .replace(/</g, '&lt;')
    .replace(/>/g, '&gt;')
    .replace(/"/g, '&quot;');
}

export class EmailNotificationAdapter implements NotificationAdapter {
  readonly channel = 'email' as const;
  private logger = new Logger('EmailAdapter');
  private sentEmails: SentEmail[] = [];

  constructor(private config: EmailConfig = defaultEmailConfig) {}

  /**
   * Send an email notification.
   * Validates recipient, renders template, and delivers via transport.
   */
  async send(payload: NotificationPayload): Promise<NotificationResult> {
    try {
      // Resolve recipient to a valid email
      const toAddress = resolveRecipient(payload.recipient, payload.metadata);

      if (!toAddress) {
        this.logger.error(
          `Cannot resolve recipient "${payload.recipient}" to a valid email address`,
        );
        return {
          success: false,
          notificationId: payload.id,
          channel: 'email',
          deliveredAt: new Date(),
          error: `Invalid recipient: ${payload.recipient}`,
        };
      }

      // Render the email template
      const ctx: TemplateContext = {
        subject: payload.subject,
        body: payload.body,
        recipient: toAddress,
        priority: payload.priority,
        metadata: payload.metadata ?? {},
      };

      const { html, text } = renderTemplate(payload.type, ctx);

      const fromDisplay = this.config.fromName
        ? `${this.config.fromName} <${this.config.from}>`
        : this.config.from;

      const rendered: RenderedEmail = {
        from: fromDisplay,
        to: toAddress,
        replyTo: this.config.replyTo ?? this.config.from,
        subject: payload.subject,
        html,
        text,
        headers: {
          'X-Notification-Id': payload.id,
          'X-Notification-Type': payload.type,
          'X-Priority': payload.priority,
        },
      };

      // Deliver (in-memory transport for now — swap for real SMTP in production)
      this.logger.info(
        `Sending email to ${toAddress}: "${payload.subject}" (from: ${this.config.from})`,
      );

      this.sentEmails.push({ payload, rendered, sentAt: new Date() });

      return {
        success: true,
        notificationId: payload.id,
        channel: 'email',
        deliveredAt: new Date(),
      };
    } catch (err) {
      const message = err instanceof Error ? err.message : 'Unknown email error';
      this.logger.error(`Failed to send email to ${payload.recipient}: ${message}`);

      return {
        success: false,
        notificationId: payload.id,
        channel: 'email',
        deliveredAt: new Date(),
        error: message,
      };
    }
  }

  /** Get all emails sent through this adapter (useful for testing). */
  getSentEmails(): SentEmail[] {
    return [...this.sentEmails];
  }

  /** Clear sent emails (useful for testing). */
  clearSentEmails(): void {
    this.sentEmails = [];
  }
}

import { describe, it, expect, beforeEach } from 'vitest';
import {
  EmailNotificationAdapter,
  isValidEmail,
  resolveRecipient,
  renderTemplate,
  defaultEmailConfig,
} from '../../src/adapters/email.adapter.js';
import type { NotificationPayload } from '../../src/models/notification.js';

function makePayload(overrides: Partial<NotificationPayload> = {}): NotificationPayload {
  return {
    id: 'notif-0001',
    type: 'order_confirmation',
    channel: 'email',
    recipient: 'alice@example.com',
    subject: 'Order Confirmation: order-1',
    body: 'Your order has been placed. Items: Widget x2. Total: $20.00',
    priority: 'normal',
    createdAt: new Date(),
    metadata: { orderId: 'order-1', userId: 'user-1' },
    ...overrides,
  };
}

describe('isValidEmail', () => {
  it('should accept valid emails', () => {
    expect(isValidEmail('alice@example.com')).toBe(true);
    expect(isValidEmail('user+tag@sub.domain.co')).toBe(true);
  });

  it('should reject invalid emails', () => {
    expect(isValidEmail('')).toBe(false);
    expect(isValidEmail('notanemail')).toBe(false);
    expect(isValidEmail('@example.com')).toBe(false);
    expect(isValidEmail('user@')).toBe(false);
    expect(isValidEmail('user@nodot')).toBe(false);
  });
});

describe('resolveRecipient', () => {
  it('should return valid email directly', () => {
    expect(resolveRecipient('alice@example.com')).toBe('alice@example.com');
  });

  it('should fall back to metadata email for non-email recipient', () => {
    expect(resolveRecipient('user-1', { email: 'alice@example.com' })).toBe('alice@example.com');
  });

  it('should return null for unresolvable recipient', () => {
    expect(resolveRecipient('user-1')).toBeNull();
    expect(resolveRecipient('user-1', {})).toBeNull();
    expect(resolveRecipient('user-1', { email: 'invalid' })).toBeNull();
  });
});

describe('renderTemplate', () => {
  const baseCtx = {
    subject: 'Test Subject',
    body: 'Test body content',
    recipient: 'alice@example.com',
    priority: 'normal' as const,
    metadata: {} as Record<string, unknown>,
  };

  it('should render order_confirmation template', () => {
    const { html, text } = renderTemplate('order_confirmation', {
      ...baseCtx,
      metadata: { orderId: 'order-1' },
    });
    expect(html).toContain('Order Confirmation');
    expect(html).toContain('order-1');
    expect(text).toBe(baseCtx.body);
  });

  it('should render order_status_update template', () => {
    const { html } = renderTemplate('order_status_update', {
      ...baseCtx,
      metadata: { previousStatus: 'pending', newStatus: 'confirmed' },
    });
    expect(html).toContain('Order Status Update');
    expect(html).toContain('pending');
    expect(html).toContain('confirmed');
  });

  it('should render welcome template', () => {
    const { html } = renderTemplate('welcome', baseCtx);
    expect(html).toContain('Welcome to TaskFlow Pro');
    expect(html).toContain('dashboard');
  });

  it('should render account_updated template', () => {
    const { html } = renderTemplate('account_updated', baseCtx);
    expect(html).toContain('Account Updated');
  });

  it('should include priority banner for high priority', () => {
    const { html } = renderTemplate('order_status_update', {
      ...baseCtx,
      priority: 'high',
      metadata: { previousStatus: 'pending', newStatus: 'cancelled' },
    });
    expect(html).toContain('Priority: HIGH');
  });

  it('should not include priority banner for normal priority', () => {
    const { html } = renderTemplate('order_confirmation', { ...baseCtx, metadata: {} });
    expect(html).not.toContain('Priority:');
  });

  it('should escape HTML in body content', () => {
    const { html } = renderTemplate('welcome', {
      ...baseCtx,
      body: 'Hello <script>alert("xss")</script>',
    });
    expect(html).not.toContain('<script>');
    expect(html).toContain('&lt;script&gt;');
  });
});

describe('EmailNotificationAdapter', () => {
  let adapter: EmailNotificationAdapter;

  beforeEach(() => {
    adapter = new EmailNotificationAdapter();
  });

  it('should have channel set to email', () => {
    expect(adapter.channel).toBe('email');
  });

  describe('send', () => {
    it('should send a valid email and return success', async () => {
      const payload = makePayload();
      const result = await adapter.send(payload);

      expect(result.success).toBe(true);
      expect(result.notificationId).toBe('notif-0001');
      expect(result.channel).toBe('email');
      expect(result.deliveredAt).toBeInstanceOf(Date);
    });

    it('should store the sent email with rendered content', async () => {
      const payload = makePayload();
      await adapter.send(payload);

      const sent = adapter.getSentEmails();
      expect(sent).toHaveLength(1);
      expect(sent[0]!.payload).toEqual(payload);
      expect(sent[0]!.rendered.to).toBe('alice@example.com');
      expect(sent[0]!.rendered.subject).toBe(payload.subject);
      expect(sent[0]!.rendered.html).toContain('Order Confirmation');
      expect(sent[0]!.rendered.headers['X-Notification-Id']).toBe('notif-0001');
      expect(sent[0]!.rendered.headers['X-Notification-Type']).toBe('order_confirmation');
    });

    it('should use configured from address', async () => {
      const customAdapter = new EmailNotificationAdapter({
        host: 'smtp.custom.com',
        port: 465,
        from: 'support@custom.com',
        fromName: 'Custom Support',
      });

      await customAdapter.send(makePayload());

      const sent = customAdapter.getSentEmails();
      expect(sent[0]!.rendered.from).toBe('Custom Support <support@custom.com>');
    });

    it('should use replyTo when configured', async () => {
      const customAdapter = new EmailNotificationAdapter({
        ...defaultEmailConfig,
        replyTo: 'replies@taskflowpro.com',
      });

      await customAdapter.send(makePayload());

      const sent = customAdapter.getSentEmails();
      expect(sent[0]!.rendered.replyTo).toBe('replies@taskflowpro.com');
    });

    it('should fail for invalid recipient without metadata fallback', async () => {
      const payload = makePayload({ recipient: 'user-1', metadata: {} });
      const result = await adapter.send(payload);

      expect(result.success).toBe(false);
      expect(result.error).toContain('Invalid recipient');
      expect(adapter.getSentEmails()).toHaveLength(0);
    });

    it('should resolve user ID recipient from metadata email', async () => {
      const payload = makePayload({
        recipient: 'user-1',
        metadata: { email: 'alice@example.com', orderId: 'order-1' },
      });
      const result = await adapter.send(payload);

      expect(result.success).toBe(true);
      const sent = adapter.getSentEmails();
      expect(sent[0]!.rendered.to).toBe('alice@example.com');
    });

    it('should render high-priority banner for high-priority payloads', async () => {
      const payload = makePayload({
        type: 'order_status_update',
        priority: 'high',
        metadata: { orderId: 'order-1', previousStatus: 'pending', newStatus: 'cancelled' },
      });
      await adapter.send(payload);

      const sent = adapter.getSentEmails();
      expect(sent[0]!.rendered.html).toContain('Priority: HIGH');
    });
  });

  describe('getSentEmails / clearSentEmails', () => {
    it('should return a copy of sent emails', async () => {
      await adapter.send(makePayload());
      const emails = adapter.getSentEmails();
      emails.pop();
      expect(adapter.getSentEmails()).toHaveLength(1);
    });

    it('should clear all sent emails', async () => {
      await adapter.send(makePayload());
      adapter.clearSentEmails();
      expect(adapter.getSentEmails()).toHaveLength(0);
    });
  });
});

describe('EmailNotificationAdapter integration with NotificationService', () => {
  it('should work end-to-end with EventBus and NotificationService', async () => {
    // Dynamic imports to avoid circular issues in test setup
    const { EventBus } = await import('../../src/events/event-bus.js');
    const { NotificationService, resetNotificationIdCounter } = await import(
      '../../src/services/notification.service.js'
    );

    const eventBus = new EventBus();
    const service = new NotificationService(eventBus);
    const adapter = new EmailNotificationAdapter();
    resetNotificationIdCounter();

    // Wire up the adapter
    service.registerAdapter(adapter);

    // Emit an event
    await eventBus.emit({
      type: 'order:created',
      order: {
        id: 'order-42',
        userId: 'user-1',
        items: [{ productId: 'p1', name: 'Widget', quantity: 3, unitPrice: 15 }],
        total: 45,
        status: 'pending',
        createdAt: new Date(),
        updatedAt: new Date(),
      },
      user: {
        id: 'user-1',
        name: 'Bob',
        email: 'bob@example.com',
        role: 'member',
        createdAt: new Date(),
        updatedAt: new Date(),
      },
      timestamp: new Date(),
    });

    // Notification should be stored as 'sent' (not 'pending')
    const notifications = service.getNotifications();
    expect(notifications).toHaveLength(1);
    expect(notifications[0]!.status).toBe('sent');
    expect(notifications[0]!.recipient).toBe('bob@example.com');

    // Email should be captured by the adapter
    const sent = adapter.getSentEmails();
    expect(sent).toHaveLength(1);
    expect(sent[0]!.rendered.to).toBe('bob@example.com');
    expect(sent[0]!.rendered.html).toContain('Order Confirmation');
    expect(sent[0]!.rendered.html).toContain('order-42');
    expect(sent[0]!.rendered.text).toContain('Widget x3');
  });
});

